// ═══════════════════════════════════════════════════════════════
// 1️⃣ INIT + VALIDATE v6.1 — Single node: normalize + validate
// Handles both: sub-workflow trigger (fields at top) and chat trigger (chatInput string)
// ═══════════════════════════════════════════════════════════════
let input = $input.first()?.json || {};
if (input.chatInput && typeof input.chatInput === 'string') {
  try { input = JSON.parse(input.chatInput); } catch { input = {}; }
}
const now = Date.now();
const trace = `agendar-${now}-${Math.random().toString(36).slice(2,10)}`;

function toMexicoISO(d) {
  if (!d) return null;
  try {
    const date = new Date(d);
    if (isNaN(date.getTime())) return null;
    const f = new Intl.DateTimeFormat('sv-SE', {
      timeZone: 'America/Mexico_City',
      year:'numeric',month:'2-digit',day:'2-digit',
      hour:'2-digit',minute:'2-digit',second:'2-digit',hour12:false
    });
    return f.format(date).replace(' ','T') + '.000-06:00';
  } catch { return null; }
}

// Extract phone
let phoneRaw = input.lead_telefono || (typeof input.paciente === 'object' ? input.paciente?.telefono : '') || input.phone || input.wa_id || input.telefono || '';
const phone = phoneRaw.toString().replace(/\D/g, '').slice(-10);

// Extract name
let name = 'Paciente';
if (input.paciente && typeof input.paciente === 'object' && input.paciente.nombre) name = input.paciente.nombre;
else if (typeof input.paciente === 'string' && input.paciente.trim()) name = input.paciente.trim();
else if (input.pacienteNombre) name = input.pacienteNombre;
else if (input.patientName) name = input.patientName;
else if (input.nombre) name = input.nombre;
name = name.replace(/["{}]/g, '').trim() || 'Paciente';

let email = (typeof input.paciente === 'object' ? input.paciente?.email : null) || input.email || null;

// Dates
const rawStart = input.start || input.startTime || '';
const rawEnd = input.end || input.endTime || '';
const startTime = toMexicoISO(rawStart);
let endTime = toMexicoISO(rawEnd);
if (!endTime && rawStart) {
  try { endTime = toMexicoISO(new Date(new Date(rawStart).getTime() + 30*60000).toISOString()); } catch {}
}

// Sede
let sede = (input.sede || '').toString().toUpperCase().trim().replace(/[^A-Z]/g, '');
if (sede.includes('SATELLITE')) sede = 'SATELITE';
if (sede.includes('POLNACO')) sede = 'POLANCO';

// Validate
const problems = [];
if (!phone || phone.length < 10) problems.push({field:'phone',hint:'Pregunta el número de WhatsApp (10 dígitos).'});
if (!sede || sede.length < 3) problems.push({field:'sede',hint:'Pregunta sede: Polanco o Satélite.'});
if (!startTime) problems.push({field:'startTime',hint:'Usa DISPONIBILIDAD_CALENDARIO para obtener horario válido.'});
else {
  const d = new Date(rawStart);
  if (isNaN(d.getTime())) problems.push({field:'startTime',hint:'Formato de fecha inválido.'});
  else {
    const nowMx = new Date(new Date().toLocaleString('en-US',{timeZone:'America/Mexico_City'}));
    if (d.getTime() < nowMx.getTime() - 5*60000) problems.push({field:'startTime',hint:'La fecha ya pasó. Usa DISPONIBILIDAD_CALENDARIO.'});
  }
}

if (problems.length > 0) {
  return {json:{success:false, error:'VALIDATION_FAILED', problems, message:'Datos incompletos.', meta:{trace}}};
}

const dateStr = startTime.replace(/[-:]/g,'').substring(0,15);
return {json:{
  phone, phoneRaw, phoneForWhatsApp: phone.startsWith('52') ? phone : `52${phone}`,
  patientName: name, patientEmail: email, sede, startTime, endTime,
  tipoCita: input.tipoCita || 'primera_vez',
  motivo: input.motivoConsulta || input.motivo || 'Consulta urológica',
  slotId: input.slotId || '',
  _trace: trace, _consulta_id: `${sede}_${phone}_${dateStr}`,
  _ok: true
}};

// ═══════════════════════════════════════════════════════════════
// 3️⃣ VALIDATE SEDE + SCHEDULE v2 — with multi-calendar support
// ═══════════════════════════════════════════════════════════════
const ctx = $('1️⃣ Init + Validate').first()?.json || {};
const sedeRow = $input.first()?.json;
const trace = ctx._trace;

if (!sedeRow || !sedeRow.calendar_id) {
  return {json:{success:false, error:'SEDE_NOT_FOUND', message:`Sede '${ctx.sede}' no configurada.`, meta:{trace}}};
}

const PERSONAL_CAL = 'mmartinezuro@gmail.com';
const otraSedeCalId = sedeRow.otra_sede_calendar_id || '';

const enriched = {
  ...ctx,
  sede_id: sedeRow.id,
  calendar_id: sedeRow.calendar_id,
  personal_calendar_id: PERSONAL_CAL,
  otra_sede_calendar_id: otraSedeCalId,
  sedeDisplayName: sedeRow.display_name,
  sedeDireccion: sedeRow.direccion,
  sedeMapsUrl: sedeRow.maps_url,
  timezone: sedeRow.timezone || 'America/Mexico_City'
};

const horario = sedeRow.horario_json;
if (horario && ctx.startTime) {
  const DAY_NAMES = ['domingo','lunes','martes','miercoles','jueves','viernes','sabado'];
  try {
    const d = new Date(ctx.startTime);
    const dayF = new Intl.DateTimeFormat('en-US',{timeZone:'America/Mexico_City',weekday:'short'});
    const hourF = new Intl.DateTimeFormat('en-US',{timeZone:'America/Mexico_City',hour:'2-digit',minute:'2-digit',hour12:false});
    const dayMap = {Sun:0,Mon:1,Tue:2,Wed:3,Thu:4,Fri:5,Sat:6};
    const dow = dayMap[dayF.format(d)];
    const [h,m] = hourF.format(d).split(':').map(Number);
    const reqTime = h*60+m;
    const dayName = DAY_NAMES[dow];
    let valid = false;
    for (const wk of ['weekA','weekB']) {
      const week = horario[wk];
      if (!week || !week[dayName]) continue;
      for (const shift of week[dayName]) {
        if (!Array.isArray(shift) || shift.length < 2) continue;
        const [sh,sm] = shift[0].split(':').map(Number);
        const [eh,em] = shift[1].split(':').map(Number);
        if (reqTime >= sh*60+sm && reqTime < eh*60+em) { valid = true; break; }
      }
      if (valid) break;
    }
    if (!valid) {
      const dayDisplay = ['domingo','lunes','martes','miércoles','jueves','viernes','sábado'][dow];
      return {json:{success:false, error:'OUTSIDE_WORKING_HOURS',
        message:`Ese horario no está disponible el ${dayDisplay}. Usa DISPONIBILIDAD_CALENDARIO.`,
        instruction:'Usa DISPONIBILIDAD_CALENDARIO para obtener horarios válidos.', meta:{trace}}};
    }
  } catch(e) { /* fail-open if parse error */ }
}

return {json:{...enriched, _ok: true}};

// ═══════════════════════════════════════════════════════════════
// 6️⃣ GATE: Duplicate + FreeBusy (3 calendars) v2
// Checks: sede calendar + personal calendar + other sede calendar
// ═══════════════════════════════════════════════════════════════
const ctx = $('3️⃣ Gate: Sede + Schedule').first()?.json || {};
const trace = ctx._trace;

// Check duplicate
const dupResult = $('4️⃣ Check Duplicate').first()?.json;
if (dupResult && dupResult.id) {
  return {json:{success:false, error:'DUPLICATE_APPOINTMENT',
    message:'Ya existe una cita en ese horario.', existingId: dupResult.consulta_id, meta:{trace}}};
}

// Check ALL 3 calendars for busy slots
const calNames = ['5️⃣a FreeBusy Sede', '5️⃣b FreeBusy Personal', '5️⃣c FreeBusy Otra Sede'];
const calIds = [ctx.calendar_id, ctx.personal_calendar_id, ctx.otra_sede_calendar_id];
let busyFound = null;
for (let i = 0; i < calNames.length; i++) {
  try {
    const fb = $(calNames[i]).first()?.json;
    if (!fb) continue;
    let busy = [];
    if (fb.calendars) {
      for (const cid of Object.keys(fb.calendars)) {
        busy = busy.concat(fb.calendars[cid].busy || []);
      }
    } else if (fb.busy) {
      busy = fb.busy;
    }
    if (busy.length > 0) {
      busyFound = calNames[i];
      break;
    }
  } catch(e) { /* calendar check failed, fail-open */ }
}
if (busyFound) {
  return {json:{success:false, error:'SLOT_NOT_AVAILABLE',
    message:`El horario ya no está disponible (conflicto en ${busyFound}). Usa DISPONIBILIDAD_CALENDARIO.`, meta:{trace}}};
}

return {json:{...ctx, _ok: true}};

// ═══════════════════════════════════════════════════════════════
// 8️⃣ GATE: Paciente — extract IDs
// ═══════════════════════════════════════════════════════════════
const ctx = $('6️⃣ Gate: Dup + FreeBusy').first()?.json || {};
const trace = ctx._trace;
const dbResult = $input.first()?.json;
const rows = Array.isArray(dbResult) ? dbResult : (dbResult?.id ? [dbResult] : []);

if (!rows.length || !rows[0]?.id) {
  return {json:{success:false, error:'PACIENTE_ERROR', message:'Error al registrar paciente.', meta:{trace}}};
}

return {json:{
  ...ctx,
  paciente_id: rows[0].id,
  lead_id: rows[0].lead_id || null,
  _ok: true
}};

// ═══════════════════════════════════════════════════════════════
// 🔟 GATE: Event — check calendar event created
// ═══════════════════════════════════════════════════════════════
const ctx = $('8️⃣ Gate: Paciente').first()?.json || {};
const trace = ctx._trace;
const eventResult = $input.first()?.json;

if (!eventResult || eventResult.error || !eventResult.id) {
  return {json:{success:false, error:'EVENT_CREATION_FAILED',
    message:'Error al crear evento en calendario.', meta:{trace}}};
}

return {json:{
  ...ctx,
  event_id: eventResult.id,
  event_link: eventResult.htmlLink || '',
  _ok: true
}};

// ═══════════════════════════════════════════════════════════════
// ✅ RETURN SUCCESS — Format response for AI Agent
// ═══════════════════════════════════════════════════════════════
const ctx = $('🔟 Gate: Event').first()?.json || {};
const trace = ctx._trace;

let fechaFormateada = ctx.startTime;
try {
  const f = new Intl.DateTimeFormat('es-MX', {
    weekday:'long',year:'numeric',month:'long',day:'numeric',
    hour:'2-digit',minute:'2-digit',hour12:true,timeZone:'America/Mexico_City'
  });
  fechaFormateada = f.format(new Date(ctx.startTime));
} catch {}

return {json:{
  success: true,
  message: 'Cita agendada exitosamente.',
  data: {
    paciente: ctx.patientName,
    sede: ctx.sedeDisplayName,
    sedeDireccion: ctx.sedeDireccion,
    fecha: fechaFormateada,
    tipoCita: ctx.tipoCita,
    motivo: ctx.motivo
  },
  meta: {
    trace,
    consulta_id: ctx._consulta_id,
    lead_id: ctx.lead_id,
    paciente_id: ctx.paciente_id
  }
}};

const ctx = $('🔟 Gate: Event').first()?.json || {};
return {json:{success:false, error:'DB_SAVE_FAILED',
  message:'Error al guardar cita. Horario liberado.',
  rollback:{attempted:true, event_id:ctx.event_id},
  meta:{trace:ctx._trace}}};
